VALUES
  ('aboriginal-a5729396-moex-00504', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於訴訟代理人，下列敘述何者錯誤？', '["訴訟代理權，因本人死亡、破產或訴訟能力喪失而消滅", "訴訟代理人有2人以上者，均得單獨代理當事人", "訴訟代理人事實上之陳述，經到場之當事人本人即時撤銷或更正者，不生效力", "訴訟代理權有欠缺而可以補正者，審判長應定期間命其補正。但得許其暫為訴訟行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00505', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲、乙、丙為必要共同訴訟之原告，甲一人單獨所為之下列訴訟行為，何者對於全體不生效力？', '["提出證據", "提起合法之上訴", "自認被告主張之事實", "依法院指示補正訴訟資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00506', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何者，免徵裁判費或聲請費？', '["對於確定之裁定聲請再審", "聲請參加訴訟", "以公益為目的之財團法人，經其目的事業主管機關許可，於章程所定目的範圍內，對侵害多數人利益之 行為人，提起不作為之訴者", "因財產權而起訴，其訴訟標的之金額或價額在新臺幣10萬元以下者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00507', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於當事人書狀，下列敘述何者錯誤？', '["為保護當事人提出於法院之附屬文件原本，他造不得請求閱覽原本，得請求閱覽其影本", "當事人所執原本未經提出者，法院因他造之聲請，應命其提出", "書狀不合程式或有其他欠缺者，審判長應定期間命其補正", "書狀之欠缺，經於期間內補正者，視其補正之書狀，與最初提出同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00508', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於審判長之訴訟指揮，下列敘述何者正確？', '["審判長對於不從其訴訟指揮之當事人，應依職權禁止其發言，但訴訟代理人不在此限", "言詞辯論由審判長開閉及指揮", "當事人已委任訴訟代理人者，審判長無須令當事人為法律上之陳述，應逕命其訴訟代理人為之", "言詞辯論須續行者，審判長應速定其期日，與前一次庭期之間隔不得超過2個月，以貫徹集中審理主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00509', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於囑託送達和公示送達，下列敘述何者正確？', '["於外國為送達而當事人之住所不明者，法院均應依職權囑託該國法院為公示送達", "應為送達之處所不明者，法院均應依職權公示送達", "於外國為送達者，雖預知無法送達，仍不得為公示送達", "於有治外法權人之住居所或事務所為送達者，得囑託外交部為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00510', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於合意停止訴訟程序，下列敘述何者正確？', '["合意停止訴訟程序之當事人，自陳明合意停止時起，如於3個月內未續行訴訟者，視為撤回其訴或上訴", "當事人得以合意停止訴訟程序。但不變期間之進行，不受影響", "當事人一造為法人或商人者，不得聲請合意停止訴訟程序。但兩造已委任訴訟代理人者，不在此限", "與公益相關之事項，當事人不得合意停止訴訟程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00511', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '如未到期之債權有預為請求之必要者，債權人得提起何種訴訟？', '["中間確認之訴", "客觀預備合併之訴", "將來給付之訴", "第三人撤銷之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00512', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '除有急迫情形或曾行準備程序之事件外，法院一併送達起訴狀與言詞辯論期日通知書於被告時，其距言詞 辯論期日，至少應有多少日為就審期間？', '["10日", "15日", "20日", "30日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00513', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲起訴請求乙給付積欠之貨款新臺幣（下同）20萬元，訴訟中甲、乙私下達成和解，約定於乙給付15萬 元後，甲即撤回起訴。乙依約給付15萬元後，甲並未撤回起訴。於乙向法院抗辯後，法院應如何處理？', '["以該訴欠缺當事人適格，駁回原告之訴", "以該訴欠缺訴之利益，駁回原告之訴", "以該訴已發生撤回之效力，毋庸繼續審判", "以該訴訟欠缺訴訟上之成立要件，駁回原告之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
